java_code:'class Solution{public int[] nextGreaterElement(int[] n1,int[] n2){Map<Integer,Integer> map=new HashMap<>();Deque<Integer> st=new ArrayDeque<>();for(int n:n2){while(!st.isEmpty()&&st.peek()<n)map.put(st.pop(),n);st.push(n);}int[] res=new int[n1.length];for(int i=0;i<n1.length;i++)res[i]=map.getOrDefault(n1[i],-1);return res;}}',
python_code:'def nextGreaterElement(n1,n2):\n    st=[];m={}\n    for n in n2:\n        while st and st[-1]<n: m[st.pop()]=n\n        st.append(n)\n    return [m.get(x,-1) for x in n1]',
cpp_code:'vector<int> nextGreaterElement(vector<int>&n1,vector<int>&n2){unordered_map<int,int>m;stack<int>st;for(int n:n2){while(!st.empty()&&st.top()<n){m[st.top()]=n;st.pop();}st.push(n);}vector<int>res;for(int x:n1)res.push_back(m.count(x)?m[x]:-1);return res;}',
