java_code:'class Solution{public List<String> generateParenthesis(int n){List<String> res=new ArrayList<>();backtrack(res,"",0,0,n);return res;}void backtrack(List<String> res,String cur,int open,int close,int n){if(cur.length()==2*n){res.add(cur);return;}if(open<n)backtrack(res,cur+"(",open+1,close,n);if(close<open)backtrack(res,cur+")",open,close+1,n);}}',
python_code:'def generateParenthesis(n):\n    res=[]\n    def bt(cur,o,c):\n        if len(cur)==2*n: res.append(cur);return\n        if o<n: bt(cur+"(",o+1,c)\n        if c<o: bt(cur+")",o,c+1)\n    bt("",0,0)\n    return res',
cpp_code:'void bt(vector<string>&res,string cur,int o,int c,int n){if((int)cur.size()==2*n){res.push_back(cur);return;}if(o<n)bt(res,cur+"(",o+1,c,n);if(c<o)bt(res,cur+")",o,c+1,n);}vector<string> generateParenthesis(int n){vector<string>res;bt(res,"",0,0,n);return res;}',
