java_code:'class Solution{public String decodeString(String s){Deque<Integer> countSt=new ArrayDeque<>();Deque<StringBuilder> strSt=new ArrayDeque<>();StringBuilder cur=new StringBuilder();int num=0;for(char c:s.toCharArray()){if(Character.isDigit(c))num=num*10+(c-\'0\');else if(c==\'[\'){countSt.push(num);strSt.push(cur);num=0;cur=new StringBuilder();}else if(c==\']\'){int cnt=countSt.pop();StringBuilder prev=strSt.pop();for(int i=0;i<cnt;i++)prev.append(cur);cur=prev;}else cur.append(c);}return cur.toString();}}',
python_code:'def decodeString(s):\n    countSt=[];strSt=[];cur="";num=0\n    for c in s:\n        if c.isdigit(): num=num*10+int(c)\n        elif c=="[": countSt.append(num);strSt.append(cur);num=0;cur=""\n        elif c=="]":\n            cnt=countSt.pop();prev=strSt.pop()\n            cur=prev+cur*cnt\n        else: cur+=c\n    return cur',
cpp_code:'string decodeString(string s){stack<int>countSt;stack<string>strSt;string cur="";int num=0;for(char c:s){if(isdigit(c))num=num*10+(c-\'0\');else if(c==\'[\'){countSt.push(num);strSt.push(cur);num=0;cur="";}else if(c==\']\'){int cnt=countSt.top();countSt.pop();string prev=strSt.top();strSt.pop();for(int i=0;i<cnt;i++)prev+=cur;cur=prev;}else cur+=c;}return cur;}',
