java_code:'class Solution{public int calculate(String s){Deque<Integer> st=new ArrayDeque<>();int num=0;char op=\'+\';for(int i=0;i<s.length();i++){char c=s.charAt(i);if(Character.isDigit(c))num=num*10+(c-\'0\');if(!Character.isDigit(c)&&c!=\' \'||i==s.length()-1){if(op==\'+\')st.push(num);else if(op==\'-\')st.push(-num);else if(op==\'*\')st.push(st.pop()*num);else if(op==\'/\')st.push(st.pop()/num);op=c;num=0;}}int res=0;while(!st.isEmpty())res+=st.pop();return res;}}',
python_code:'def calculate(s):\n    st=[];num=0;op="+"\n    for i,c in enumerate(s):\n        if c.isdigit(): num=num*10+int(c)\n        if (not c.isdigit() and c!=" ") or i==len(s)-1:\n            if op=="+": st.append(num)\n            elif op=="-": st.append(-num)\n            elif op=="*": st.append(st.pop()*num)\n            elif op=="/": st.append(int(st.pop()/num))\n            op=c;num=0\n    return sum(st)',
cpp_code:'int calculate(string s){stack<int>st;int num=0;char op=\'+\';for(int i=0;i<(int)s.size();i++){char c=s[i];if(isdigit(c))num=num*10+(c-\'0\');if((!isdigit(c)&&c!=\' \')||i==(int)s.size()-1){if(op==\'+\')st.push(num);else if(op==\'-\')st.push(-num);else if(op==\'*\'){int t=st.top();st.pop();st.push(t*num);}else if(op==\'/\'){int t=st.top();st.pop();st.push(t/num);}op=c;num=0;}}int res=0;while(!st.empty()){res+=st.top();st.pop();}return res;}',
