java_code:'class Solution{public int largestRectangleArea(int[] h){Deque<Integer> st=new ArrayDeque<>();int max=0;for(int i=0;i<=h.length;i++){int cur=(i==h.length)?0:h[i];while(!st.isEmpty()&&h[st.peek()]>=cur){int height=h[st.pop()];int width=st.isEmpty()?i:i-st.peek()-1;max=Math.max(max,height*width);}st.push(i);}return max;}}',
