hint:'Monotonic decreasing deque storing indices.',approach:'Remove expired indices from front, remove smaller elements from back before pushing.',
java_code:'class Solution{public int[] maxSlidingWindow(int[] n,int k){Deque<Integer> dq=new ArrayDeque<>();int[] res=new int[n.length-k+1];for(int i=0;i<n.length;i++){while(!dq.isEmpty()&&dq.peekFirst()<i-k+1)dq.pollFirst();while(!dq.isEmpty()&&n[dq.peekLast()]<n[i])dq.pollLast();dq.offerLast(i);if(i>=k-1)res[i-k+1]=n[dq.peekFirst()];}return res;}}',
python_code:'from collections import deque\ndef maxSlidingWindow(n,k):\n    dq=deque();res=[]\n    for i,x in enumerate(n):\n        while dq and dq[0]<i-k+1: dq.popleft()\n        while dq and n[dq[-1]]<x: dq.pop()\n        dq.append(i)\n        if i>=k-1: res.append(n[dq[0]])\n    return res',
cpp_code:'vector<int> maxSlidingWindow(vector<int>&n,int k){deque<int>dq;vector<int>res;for(int i=0;i<(int)n.size();i++){while(!dq.empty()&&dq.front()<i-k+1)dq.pop_front();while(!dq.empty()&&n[dq.back()]<n[i])dq.pop_back();dq.push_back(i);if(i>=k-1)res.push_back(n[dq.front()]);}return res;}',
