hint:'Greedy with a monotonic increasing stack.',approach:'Pop larger digits from stack while k>0 and current digit is smaller, then push current.',
java_code:'class Solution{public String removeKdigits(String num,int k){Deque<Character> st=new ArrayDeque<>();for(char c:num.toCharArray()){while(!st.isEmpty()&&k>0&&st.peek()>c){st.pop();k--;}st.push(c);}while(k-->0)st.pop();StringBuilder sb=new StringBuilder();while(!st.isEmpty())sb.append(st.pollLast());while(sb.length()>1&&sb.charAt(0)==\'0\')sb.deleteCharAt(0);return sb.length()==0?"0":sb.toString();}}',
python_code:'def removeKdigits(num,k):\n    st=[]\n    for c in num:\n        while st and k>0 and st[-1]>c:\n            st.pop();k-=1\n        st.append(c)\n    st=st[:len(st)-k] if k>0 else st\n    res="".join(st).lstrip("0")\n    return res if res else "0"',
cpp_code:'string removeKdigits(string num,int k){string st="";for(char c:num){while(!st.empty()&&k>0&&st.back()>c){st.pop_back();k--;}st.push_back(c);}while(k-->0)st.pop_back();int i=0;while(i<(int)st.size()-1&&st[i]==\'0\')i++;st=st.substr(i);return st.empty()?"0":st;}',
