hint:'Split by /, use a stack: push valid names, pop on "..".',approach:'Tokenize by /, ignore "." and empty, pop stack on "..", else push token.',
java_code:'class Solution{public String simplifyPath(String path){Deque<String> st=new ArrayDeque<>();for(String p:path.split("/")){if(p.isEmpty()||p.equals("."))continue;if(p.equals("..")){if(!st.isEmpty())st.pop();}else st.push(p);}StringBuilder sb=new StringBuilder();for(String s:st)sb.insert(0,"/"+s);return sb.length()==0?"/":sb.toString();}}',
python_code:'def simplifyPath(path):\n    st=[]\n    for p in path.split("/"):\n        if p=="" or p==".": continue\n        if p=="..":\n            if st: st.pop()\n        else: st.append(p)\n    return "/"+"/".join(st)',
cpp_code:'string simplifyPath(string path){vector<string>st;stringstream ss(path);string tok;while(getline(ss,tok,\'/\')){if(tok==""||tok==".")continue;if(tok==".."){if(!st.empty())st.pop_back();}else st.push_back(tok);}string res="";for(auto&s:st)res+="/"+s;return res.empty()?"/":res;}',
